'use strict';

module.exports = (client, packet) => {
  const data = packet.d; 

  if (!client._watchedUsers) client._watchedUsers = new Set();
  if (!client._stalkAllUsers) client._stalkAllUsers = new Set();
  
  const authorId = data.author?.id;
  const isClientMessage = authorId === client.user?.id;
  const isStalkedUser = authorId && client._watchedUsers.has(authorId);
  const isStalkAllUser = authorId && client._stalkAllUsers.has(authorId);
  
  if (isClientMessage) {
    client.actions.MessageCreate.handle(data);
    return;
  }
    
  const messageKey = `${data.channel_id}_${data.id}`;
  if (!client._afkProcessed) client._afkProcessed = new Set();
   
  const emitAfkCheck = () => { 
    if (client._afkProcessed.has(messageKey)) {
      return;
    }
    client._afkProcessed.add(messageKey);
     
    setTimeout(() => {
      client._afkProcessed.delete(messageKey);
    }, 5000);
    
    setTimeout(() => {
      const channel = client.channels.cache.get(data.channel_id);
      if (channel && channel.isText()) {
        const { Message } = require('discord.js');
        const message = new Message(client, data, channel); 
        const isDM = channel.type === 'DM';
        const hasMention = data.mentions && data.mentions.some(m => m.id === client.user?.id);
        
        if ((isDM || hasMention) && client._afkInitialized) { 
          client.emit('afkCheck', message);
        }
      }
    }, 50);
  };
   
  emitAfkCheck();
   
  if (isStalkAllUser) {
    const stalkedData = {
      ...data,
      _isStalkedAllMessage: true,
      _stalkTimestamp: Date.now()
    };
    
    client.actions.MessageCreate.handle(stalkedData);
  } 
  else if (isStalkedUser && !isStalkAllUser) {
    const stalkedData = {
      ...data,
      _isStalkedMessage: true,
      _stalkTimestamp: Date.now()
    };
    
    client.actions.MessageCreate.handle(stalkedData);
  } else { 
    client.actions.MessageCreate.handle(data);
  }
};